    }

    #[test]
    fn test_sparse_builder() {
        let mut builder = SparseRandomEffectsBuilder::new(10, 5);
        builder.add_entry(0, 0, 1.0);
        builder.add_entry(1, 0, 1.0);
        builder.add_entry(2, 1, 1.0);

        let sparse_matrix = builder.build();
        assert_eq!(sparse_matrix.rows(), 10);
        assert_eq!(sparse_matrix.cols(), 5);
        assert_eq!(sparse_matrix.nnz(), 3);
    }

    #[test]
    fn test_config_defaults() {
        let config = MixedModelConfig::default();
        assert_eq!(config.max_iter, 200);
        assert_eq!(config.param_tolerance, 1e-6);
        assert_eq!(config.loglik_tolerance, 1e-8);
        assert!(config.use_reml);
        assert_eq!(config.nquad, 15);
        assert!(config.parallel);
    }
