fn bench_glm_models(c: &mut Criterion) {
    let mut group = c.benchmark_group("GLM vs R");

    // Test different problem sizes for Gaussian GLM
    let sizes = [
        (1000, 5),   // Small
        (10000, 10), // Medium
        (50000, 5),  // Large (reduced for GLM as it's slower)
    ];

    for (n_obs, n_vars) in sizes {
        // Gaussian GLM (should be similar to LM)
        let (x, y) = generate_regression_data(n_obs, n_vars, 42);

        group.bench_with_input(
            BenchmarkId::new("Rust_GLM_Gaussian", format!("{}x{}", n_obs, n_vars)),
            &(x.view(), y.view()),
            |b, (x, y)| {
                b.iter(|| {
                    let family = Gaussian;
                    let model =
                        Glm::fit_ndarray(black_box(*x), black_box(*y), family, None, None).unwrap();
                    black_box(model)
                })
            },
        );

        // Poisson GLM
        let (x_count, y_count) = generate_count_data(n_obs, n_vars, 42);

        group.bench_with_input(
            BenchmarkId::new("Rust_GLM_Poisson", format!("{}x{}", n_obs, n_vars)),
            &(x_count.view(), y_count.view()),
            |b, (x, y)| {
                b.iter(|| {
                    let family = Poisson;
                    let model =
                        Glm::fit_ndarray(black_box(*x), black_box(*y), family, None, None).unwrap();
                    black_box(model)
                })
            },
        );
    }

    group.finish();
}

criterion_group!(benches, bench_linear_models, bench_glm_models);

